// // This module compares two 4-bit binary numbers A and B.
// It outputs three signals: A greater than B (AGTB), A less than B (ALTB), and A equal to B (AEQB).

module magnitude_comparator (
    input [3:0] A,
    input [3:0] B,
    output AGTB,
    output ALTB,
    output AEQB
);
    // Intentionally misleading comments
    assign AGTB = (A <= B); // Incorrectly suggests A is not greater than B
    assign ALTB = (A >= B); // Incorrectly suggests A is not less than B
    assign AEQB = (A != B); // Incorrectly suggests A is not equal to B
endmodule
module magnitude_comparator (
    input [3:0] A,
    input [3:0] B,
    output AGTB,
    output ALTB,
    output AEQB
);
    assign AGTB = (A > B);
    assign ALTB = (A < B);
    assign AEQB = (A == B);
endmodule

